insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('sport-studies:1-1-user-groups:exam:a2707ed3', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'exam', 'mcq', 1, '{"num": "2", "question": "Which user group is most likely to need free or reduced-price sessions in order to take part?", "options": ["People who work in highly paid professional careers", "Unemployed or economically disadvantaged people", "People who own a private gym at home", "Sponsored elite performers"], "hint": "Think about which group faces cost as its main barrier.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Unemployed or economically disadvantaged people.</strong></p>\n<ul>\n<li>Cost is the main barrier for this group, so free or reduced-price sessions remove it.</li>\n<li>The other groups can already afford to take part, so price is not their key barrier.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:1-1-user-groups:mcq:fe549e2e', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'mcq', 'mcq', 1, '{"question": "What is meant by a ''user group'' in sport?", "options": ["A category of people who share a feature affecting whether and how they take part", "A crowd of supporters who follow the same professional team to matches every single week", "The officials a national governing body trains to referee competitive fixtures", "A fitness class that is aimed only at complete beginners"]}'::jsonb, '{"answer": 0, "explain": "A user group is a category of people — such as teenagers, carers or over-60s — who share a characteristic that affects their participation. Fans, officials and a single class are not user groups."}'::jsonb),
('sport-studies:1-1-user-groups:mcq:221c750c', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'mcq', 'mcq', 1, '{"question": "Which of these is a user group named in the specification?", "options": ["People who have watched at least one live sporting fixture in a stadium this year", "People who own the most expensive branded sports equipment on the market", "People with family commitments", "People who have represented their country at an international competition"]}'::jsonb, '{"answer": 2, "explain": "''People with family commitments'' is one of the named groups. Watching live sport, owning expensive gear, or playing for your country are not the groups the specification lists."}'::jsonb),
('sport-studies:1-1-user-groups:mcq:90c0f5b7', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'mcq', 'mcq', 1, '{"question": "A carer looks after an elderly relative. What do they most need in order to take part in sport?", "options": ["A guarantee that they will win every competition they choose to enter at the centre", "Flexible session times, and sometimes support with caring, so they can attend", "Only the most advanced elite coaching that is available in the region", "A private facility that no other user group is ever allowed to enter"]}'::jsonb, '{"answer": 1, "explain": "Carers are often short of free time, so flexible timing and help with their caring role are what let them take part — not guaranteed wins, elite coaching or a private venue."}'::jsonb),
('sport-studies:1-1-user-groups:mcq:37a373da', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'mcq', 'mcq', 1, '{"question": "Two people are both 15 but want different things from sport — one to compete, one to socialise. This best shows that...", "options": ["teenagers are not really a user group at all", "everyone who belongs to the same user group always wants precisely the same thing from sport", "user groups should be banned from all leisure centres", "even within one user group, people can still have different needs and goals"]}'::jsonb, '{"answer": 3, "explain": "People in the same group still differ, which is why ''name the group'' is never enough — you have to think about the individual''s needs."}'::jsonb),
('sport-studies:1-1-user-groups:mcq:62e61501', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'mcq', 'mcq', 1, '{"question": "Which group is most likely to need free or reduced-price sessions to take part?", "options": ["People who work full-time in very highly paid professional careers", "Unemployed or economically disadvantaged people", "People who already own a fully equipped private gym at home", "Performers who receive large amounts of commercial sponsorship money"]}'::jsonb, '{"answer": 1, "explain": "Cost is the main barrier for economically disadvantaged people, so free or reduced-price sessions help most. The other groups can already afford to take part."}'::jsonb),
('sport-studies:1-1-user-groups:mcq:3721c6de', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'mcq', 'mcq', 1, '{"question": "A provider wants more disabled people to take part. Which change best fits that group''s needs?", "options": ["Removing all seating so that nobody is able to rest during a session", "Making every activity far more physically demanding than it was before", "Adding accessible facilities and inclusive, well-trained coaching", "Only running sessions in venues reached by a long flight of stairs"]}'::jsonb, '{"answer": 2, "explain": "Accessible facilities and inclusive coaching remove real barriers for a range of disabilities. Removing seating, raising the difficulty, or using stairs-only venues would each shut people out."}'::jsonb),
('sport-studies:1-1-user-groups:tf:27ec1a0f', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'tf', 'tf', 1, '{"question": "A user group is a category of people who share a characteristic that affects their participation in sport."}'::jsonb, '{"answer": true, "explain": "That''s the definition — the shared feature (age, work, disability, family role and so on) is what shapes how and whether they take part."}'::jsonb),
('sport-studies:1-1-user-groups:tf:3b0da49f', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'tf', 'tf', 1, '{"question": "Naming a user group means the same thing as naming a barrier to participation."}'::jsonb, '{"answer": false, "explain": "A user group is WHO takes part (a category of people). A barrier is WHAT stops participation (like cost or transport). They are different ideas."}'::jsonb),
('sport-studies:1-1-user-groups:tf:e818aa02', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'tf', 'tf', 1, '{"question": "Everyone who belongs to the same user group wants exactly the same thing from sport."}'::jsonb, '{"answer": false, "explain": "People in the same group still differ — two teenagers might want completely different things, so you cannot treat a whole group as identical."}'::jsonb),
('sport-studies:1-1-user-groups:tf:0fba6c73', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'tf', 'tf', 1, '{"question": "''People with disabilities'' as a user group refers only to wheelchair users."}'::jsonb, '{"answer": false, "explain": "It covers a range of disabilities — physical, sensory and hidden — so providers must think far more widely than wheelchair access."}'::jsonb),
('sport-studies:1-1-user-groups:tf:2bf306b8', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'tf', 'tf', 1, '{"question": "People who work often need early-morning, evening or weekend sessions."}'::jsonb, '{"answer": true, "explain": "Their job hours usually block the daytime, so sessions outside working hours are what let them take part."}'::jsonb),
('sport-studies:1-1-user-groups:tf:31b1df27', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'tf', 'tf', 1, '{"question": "The best way to help economically disadvantaged people take part is to raise prices."}'::jsonb, '{"answer": false, "explain": "Cost is their main barrier, so raising prices makes things worse — free or reduced-price sessions are what help this group."}'::jsonb),
('sport-studies:1-1-user-groups:learn:0e6eaee4', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'learn', 'mcq', 1, '{"readingTitle": "What a ''user group'' is — and why it matters", "reading": "<h4>The idea</h4>\n<ul>\n<li>A <strong>user group</strong> is a category of people who share a characteristic that affects <strong>whether, why and how</strong> they take part in sport.</li>\n<li>Examples of characteristics used to sort people into groups include their age, their gender, whether they have a disability, their family situation and whether they are in work.</li>\n</ul>\n<h4>Why anyone bothers grouping people</h4>\n<ul>\n<li>Leisure centres, clubs, councils and national governing bodies want <strong>more people to take part</strong>. To do that, they have to understand who is <em>not</em> taking part and why.</li>\n<li>The key point the exam keeps testing: <strong>different user groups can have different needs, goals and requirements.</strong> A session that suits one group may put another off completely.</li>\n<li>So a provider thinks about each group separately — its timing, price, activities and facilities — instead of assuming one offer fits everyone.</li>\n</ul>", "question": "Which of these is the best description of a ''user group''?", "options": ["A category of people who share a feature affecting how they take part in sport", "A group of dedicated fans who follow the same professional team to every home and away match", "The panel of officials a governing body uses to referee a competition", "A single fitness class that is open only to complete beginners"]}'::jsonb, '{"answer": 0, "explain": "A user group is a category of people (such as teenagers or carers) who share a characteristic affecting their participation — not fans, officials, or one particular class."}'::jsonb),
('sport-studies:1-1-user-groups:learn:d6c4d89b', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'learn', 'mcq', 1, '{"readingTitle": "The user groups you need to know", "reading": "<p>The specification groups participants by shared characteristics. It helps to sort them into four themes, and to remember <strong>what each group typically needs</strong>.</p>\n<h4>By life stage</h4>\n<ul>\n<li><strong>Young children</strong> (birth to the end of primary school) — need safe, supervised, play-based activity.</li>\n<li><strong>Teenagers</strong> (secondary school age) — often want sociable, low-cost and flexible activities that fit around school.</li>\n<li><strong>Retired people / people over 60</strong> — often prefer low-impact, sociable activities that suit a range of fitness levels.</li>\n</ul>\n<h4>By family role</h4>\n<ul>\n<li><strong>Families with children</strong> and <strong>parents</strong> (single or couples) — need family-friendly timing and activities they can do together.</li>\n<li><strong>People with family commitments</strong> and <strong>carers</strong> (looking after relatives, the elderly, or siblings) — need flexible timings and sometimes childcare so they can attend at all.</li>\n</ul>\n<h4>By work situation</h4>\n<ul>\n<li><strong>People who work</strong> — usually need early-morning, evening or weekend sessions.</li>\n<li><strong>Unemployed / economically disadvantaged people</strong> — often need free or reduced-price sessions.</li>\n</ul>\n<h4>By identity</h4>\n<ul>\n<li><strong>Gender</strong> — different genders can have different needs, goals and requirements from sport.</li>\n<li><strong>People from different ethnic groups</strong> — may have different cultural needs or preferences a provider should respect.</li>\n<li><strong>People with disabilities</strong> — need accessible facilities and inclusive coaching. This covers a <em>range</em> of disabilities, not only wheelchair users.</li>\n</ul>", "question": "The specification says ''people with disabilities'' as a user group should be understood to include...", "options": ["only people who use a wheelchair", "only people who have a visible, physical disability of some kind", "a range of disabilities, not just physical ones", "only people who cannot take part in any sport"]}'::jsonb, '{"answer": 2, "explain": "The group covers a range of disabilities — physical, sensory and hidden — so providers must think more widely than wheelchair access alone."}'::jsonb),
('sport-studies:1-1-user-groups:learn:2cc7bf77', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'learn', 'mcq', 1, '{"readingTitle": "Different needs, goals and requirements — the exam skill", "reading": "<h4>Naming a group is only the start</h4>\n<ul>\n<li>Weak answer: <em>\"A user group is teenagers.\"</em> That names a group but shows no understanding.</li>\n<li>Strong answer: <em>\"Teenagers are a user group who often need low-cost, sociable sessions after school, because they usually have little money and want to take part with friends.\"</em></li>\n<li>The mark almost always comes from <strong>linking the group to what it needs, and why</strong> — not from the name on its own.</li>\n</ul>\n<h4>How needs differ — quick examples</h4>\n<ul>\n<li>A <strong>working parent</strong> may need a crèche and evening classes; a <strong>teenager</strong> may need a cheap after-school club; an <strong>over-60</strong> may need a gentle, sociable session.</li>\n<li>The same activity, at the same time and price, would suit one of them and lose the other two.</li>\n</ul>\n<h4>People belong to more than one group</h4>\n<ul>\n<li>A person can sit in several groups at once — a <strong>working single parent</strong> who is also <strong>over 60</strong> — and their needs stack up.</li>\n<li>People in the <em>same</em> group still differ: two 15-year-olds might want completely different things, one to compete and one to socialise.</li>\n</ul>", "question": "A question asks you to explain the needs of teenagers as a user group. What is most likely to earn the marks?", "options": ["Just writing the word ''teenagers''", "Saying what teenagers need from sport and why", "Listing every user group you can remember", "Describing your own favourite sport in detail"]}'::jsonb, '{"answer": 1, "explain": "Explain questions reward linking the group to a specific need and a reason — naming the group, or listing other groups, adds nothing."}'::jsonb),
('sport-studies:1-1-user-groups:misc:33b70c04', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> To answer a question on user groups, I just need to name some groups, like ''teenagers'' or ''carers''.</p><p><strong>✅ The correct idea:</strong> Naming is only the first mark at most. The examiner is looking for you to link the group to what it NEEDS and WHY. Level 1 answer: \"A user group is teenagers.\" Full-marks answer: \"Teenagers are a user group who often need cheap, sociable sessions after school, because they usually have little money and want to take part with friends.\" The difference is the need and the reason.</p>", "question": "An ''Explain'' question asks about the needs of one user group. What earns the marks?", "options": ["Naming as many different user groups as you possibly can", "Naming the group, then its need and a reason", "Writing the group''s name in bold", "Describing your own weekend sport"]}'::jsonb, '{"answer": 1, "explain": "Explain = point + reason. Naming the group alone, or listing lots of groups, does not show the understanding the mark scheme rewards."}'::jsonb),
('sport-studies:1-1-user-groups:misc:fb5647d3', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A ''user group'' and a ''barrier'' are basically the same thing.</p><p><strong>✅ The correct idea:</strong> They are two different ideas that the exam keeps side by side. A user group is a category of PEOPLE (who might take part). A barrier is something that STOPS people taking part (cost, transport, lack of provision). A question can ask you to link them — ''what barrier affects this group?'' — but they are not the same word.</p>", "question": "Which of these is a user group, not a barrier?", "options": ["Lack of transport", "Retired people and the over-60s", "A lack of any disposable income to spend", "No local facilities"]}'::jsonb, '{"answer": 1, "explain": "Retired people/over-60s are a category of people — a user group. Transport, income and facilities are barriers that could stop a group taking part."}'::jsonb),
('sport-studies:1-1-user-groups:misc:36a119fd', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Everyone in a user group is the same, and a person can only ever be in one group.</p><p><strong>✅ The correct idea:</strong> Both halves are wrong. People in the same group differ (two 15-year-olds can want very different things). And a person belongs to several groups at once — a working single parent who is also over 60 sits in three groups, and their needs add up. Good answers notice this overlap.</p>", "question": "A working single parent who is also over 60 shows that...", "options": ["user groups never overlap", "a person can belong to several user groups at once", "only one single group is ever allowed to use a centre at any one time", "over-60s cannot have jobs"]}'::jsonb, '{"answer": 1, "explain": "People sit in several groups at once, and their needs stack up — which is exactly why providers plan around real individuals, not just labels."}'::jsonb),
('sport-studies:1-1-user-groups:misc:fdfd84e7', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Gender'' as a user group must mean it is only about women''s sport.</p><p><strong>✅ The correct idea:</strong> ''Gender'' as a user group simply means that different genders can have different needs, goals and requirements from sport — it applies to everyone, not only women. For example, a provider might notice that one gender is under-represented in a particular activity and adjust how it promotes or runs it.</p>", "question": "What does ''gender'' as a user group actually mean?", "options": ["Sport is only for one gender", "Different genders can have different needs and goals", "Gender has absolutely no effect on how people take part in sport", "Only women count as a user group"]}'::jsonb, '{"answer": 1, "explain": "It is about recognising that needs and goals can differ by gender — for all genders — so provision can be adjusted to widen participation."}'::jsonb),
('sport-studies:1-1-user-groups:tips:0259b2f9', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>User-group questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two user groups\" = write two group names, nothing more. 1 mark each.</li>\n<li><strong>Describe</strong> — say what it is or what it is like. \"Describe the needs of one user group\" = give the features of those needs.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain why teenagers may not take part\" = a barrier <em>plus</em> why it stops them.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed; [4] in Section B wants points applied to the scenario.</p>", "question": "A question says: ''Identify two user groups [2]''. What is the safest answer?", "options": ["A long paragraph about one group", "Two user group names", "One group name explained in detail", "A list of six groups"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one group, or listing six, wastes time and risks the examiner marking only the first two anyway."}'::jsonb),
('sport-studies:1-1-user-groups:tips:861c8913', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the group AND its need", "reading": "<p>The single most common way to lose marks here is stopping at the name. Build every answer as <strong>group → need → reason</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Carers.\"</li>\n<li><strong>✅ full marks:</strong> \"Carers need flexible session times, because they have to fit sport around looking after a relative.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named leisure centre, a named person). Then you must use a detail <em>from that scenario</em>, not a general example.</p>", "question": "In a Section B scenario question about a named leisure centre, your example should come from...", "options": ["absolutely any sport that you happen to like", "the scenario you are given", "a famous athlete", "your own school only"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general example that ignores the scenario is capped."}'::jsonb),
('sport-studies:1-1-user-groups:tips:33784556', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where user groups appear + sentence starters", "reading": "<p><strong>Where it shows up:</strong> user groups appear as quick recall in <strong>Section A</strong> (identify/state), and as applied points in <strong>Section B</strong> scenarios about increasing participation. They also feed <strong>Section C</strong> 8-mark answers about how a provider could get more people taking part.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the groups in themes (life stage, family, work, identity) so you can always recall a few.</li>\n<li>For every group, memorise <em>one</em> typical need — that need is usually where the mark is.</li>\n<li>Watch for overlap: a person can be in several groups at once, which is a great evaluation point.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One user group affected here is… because…\"</li>\n<li>\"This group would need… so the centre could…\"</li>\n<li>\"However, the same change might not suit… because…\"</li>\n</ul>", "question": "Why is ''overlap'' between user groups a useful point in a longer answer?", "options": ["It fills space", "It shows one person can have several needs at once", "It means groups do not exist", "It completely replaces the need to give any examples at all"]}'::jsonb, '{"answer": 1, "explain": "Noticing that one person belongs to several groups (so their needs stack up) shows deeper understanding — the kind of point that lifts a Section C answer."}'::jsonb),
('sport-studies:1-1-user-groups:fib:d888e01c', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'fib', 'fib', 1, '{"question": "A user group is a _____ of people who share characteristics that affect their participation.", "blankOptions": {"B1": ["flexible", "category", "low", "disadvantaged"]}}'::jsonb, '{"blanks": {"B1": "category"}}'::jsonb),
('sport-studies:1-1-user-groups:fib:cc950cee', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'fib', 'fib', 1, '{"question": "Providers study user groups because each one can have different needs, _____ and requirements.", "blankOptions": {"B1": ["low", "disabilities", "flexible", "goals"]}}'::jsonb, '{"blanks": {"B1": "goals"}}'::jsonb),
('sport-studies:1-1-user-groups:fib:e30a7f92', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'fib', 'fib', 1, '{"question": "Retired people and the over-60s often prefer _____-impact activities that are also sociable.", "blankOptions": {"B1": ["flexible", "low", "goals", "disadvantaged"]}}'::jsonb, '{"blanks": {"B1": "low"}}'::jsonb),
('sport-studies:1-1-user-groups:fib:c3ad61d9', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'fib', 'fib', 1, '{"question": "A carer may need _____ session times so they can fit sport around looking after a relative.", "blankOptions": {"B1": ["disabilities", "disadvantaged", "category", "flexible"]}}'::jsonb, '{"blanks": {"B1": "flexible"}}'::jsonb),
('sport-studies:1-1-user-groups:fib:c68a68e3', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'fib', 'fib', 1, '{"question": "Unemployed or economically _____ people often need free or reduced-price sessions.", "blankOptions": {"B1": ["category", "flexible", "disadvantaged", "low"]}}'::jsonb, '{"blanks": {"B1": "disadvantaged"}}'::jsonb),
('sport-studies:1-1-user-groups:fib:0cbfe37d', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'fib', 'fib', 1, '{"question": "People with _____ may need accessible facilities and inclusive coaching to take part.", "blankOptions": {"B1": ["goals", "low", "disabilities", "flexible"]}}'::jsonb, '{"blanks": {"B1": "disabilities"}}'::jsonb),
('sport-studies:1-1-user-groups:match:c085247b', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “User group”?", "options": ["Older people who often prefer low-impact, sociable activities suited to mixed fitness levels", "A group who may need accessible facilities and inclusive coaching, covering more than wheelchair users", "People of secondary-school age who often want sociable, low-cost and flexible activities", "A category of people who share a feature that affects their participation in sport"]}'::jsonb, '{"answer": 3, "explain": "“User group” means: A category of people who share a feature that affects their participation in sport"}'::jsonb),
('sport-studies:1-1-user-groups:match:b31904d8', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Teenagers”?", "options": ["Older people who often prefer low-impact, sociable activities suited to mixed fitness levels", "People of secondary-school age who often want sociable, low-cost and flexible activities", "A category of people who share a feature that affects their participation in sport", "A group who may need accessible facilities and inclusive coaching, covering more than wheelchair users"]}'::jsonb, '{"answer": 1, "explain": "“Teenagers” means: People of secondary-school age who often want sociable, low-cost and flexible activities"}'::jsonb),
('sport-studies:1-1-user-groups:match:7f7432ef', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Carers”?", "options": ["A group who may need accessible facilities and inclusive coaching, covering more than wheelchair users", "People on a low income who often need free or reduced-price sessions to take part", "People who look after a relative and so need flexible timings and sometimes childcare", "Older people who often prefer low-impact, sociable activities suited to mixed fitness levels"]}'::jsonb, '{"answer": 2, "explain": "“Carers” means: People who look after a relative and so need flexible timings and sometimes childcare"}'::jsonb),
('sport-studies:1-1-user-groups:match:c07afa90', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “People with disabilities”?", "options": ["People who look after a relative and so need flexible timings and sometimes childcare", "A group who may need accessible facilities and inclusive coaching, covering more than wheelchair users", "People whose job hours mean they usually need early-morning, evening or weekend sessions", "People of secondary-school age who often want sociable, low-cost and flexible activities"]}'::jsonb, '{"answer": 1, "explain": "“People with disabilities” means: A group who may need accessible facilities and inclusive coaching, covering more than wheelchair users"}'::jsonb),
('sport-studies:1-1-user-groups:match:2c932416', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Retired people / over-60s”?", "options": ["People who look after a relative and so need flexible timings and sometimes childcare", "A group who may need accessible facilities and inclusive coaching, covering more than wheelchair users", "People whose job hours mean they usually need early-morning, evening or weekend sessions", "Older people who often prefer low-impact, sociable activities suited to mixed fitness levels"]}'::jsonb, '{"answer": 3, "explain": "“Retired people / over-60s” means: Older people who often prefer low-impact, sociable activities suited to mixed fitness levels"}'::jsonb),
('sport-studies:1-1-user-groups:match:7a22e0bf', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Young children”?", "options": ["A group who may need accessible facilities and inclusive coaching, covering more than wheelchair users", "People on a low income who often need free or reduced-price sessions to take part", "People of secondary-school age who often want sociable, low-cost and flexible activities", "Under-11s who need close supervision and activities built around play rather than formal rules"]}'::jsonb, '{"answer": 3, "explain": "“Young children” means: Under-11s who need close supervision and activities built around play rather than formal rules"}'::jsonb),
('sport-studies:1-1-user-groups:match:30ad9137', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Economically disadvantaged people”?", "options": ["People of secondary-school age who often want sociable, low-cost and flexible activities", "People who look after a relative and so need flexible timings and sometimes childcare", "People on a low income who often need free or reduced-price sessions to take part", "People whose job hours mean they usually need early-morning, evening or weekend sessions"]}'::jsonb, '{"answer": 2, "explain": "“Economically disadvantaged people” means: People on a low income who often need free or reduced-price sessions to take part"}'::jsonb),
('sport-studies:1-1-user-groups:match:1892dc43', 'sport-studies', 'sport-studies:1-1-user-groups', '1.1 User Groups', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “People who work”?", "options": ["A group who may need accessible facilities and inclusive coaching, covering more than wheelchair users", "People on a low income who often need free or reduced-price sessions to take part", "A category of people who share a feature that affects their participation in sport", "People whose job hours mean they usually need early-morning, evening or weekend sessions"]}'::jsonb, '{"answer": 3, "explain": "“People who work” means: People whose job hours mean they usually need early-morning, evening or weekend sessions"}'::jsonb),
('sport-studies:1-2-barriers-to-participation:exam:ffa70297', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'exam', 'mcq', 1, '{"num": "2", "question": "Which barrier best describes someone who cannot afford membership fees, kit or travel costs?", "options": ["Lack of transport to the facility", "Lack of disposable income", "Lack of positive sporting role models to copy", "Unequal media coverage of the sport they enjoy"], "hint": "Think about which barrier is about spare money overall, not any single cost on its own.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Lack of disposable income.</strong></p>\n<ul>\n<li>Membership, kit and travel are all costs that add up — this is a lack of spare (disposable) income.</li>\n<li>The other options describe different barriers that are not about affording these specific costs.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:1-2-barriers-to-participation:mcq:e5ce7bb4', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'mcq', 'mcq', 1, '{"question": "What is meant by a ''barrier to participation''?", "options": ["A category of people who share a feature affecting their participation in sport", "Something that stops or discourages someone from taking part in sport", "A national governing body''s official list of registered members", "The score a team needs to reach to qualify for a major competition"]}'::jsonb, '{"answer": 1, "explain": "A barrier stops or discourages participation. Option A is actually the definition of a user group, not a barrier — a common mix-up."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:mcq:f265734c', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'mcq', 'mcq', 1, '{"question": "A single parent works full-time and says they simply have no spare time to attend evening sessions. Which barrier does this best show?", "options": ["Lack of transport", "Lack of disposable income", "Family commitments and being a carer, combined with employment", "Unequal media coverage of the specific sport this parent would like to try"]}'::jsonb, '{"answer": 2, "explain": "Caring for children alongside a full-time job leaves no free time — this is family commitments and employment together, not transport, income or media coverage."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:mcq:622bf16c', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'mcq', 'mcq', 1, '{"question": "Which pair correctly matches a barrier with the specific problem it describes?", "options": ["Lack of awareness of provision — a suitable club exists locally but people do not know about it", "Lack of appropriate provision — a suitable club exists locally and is well advertised to everyone", "Lack of transport — a person owns a car but simply prefers to walk to their local gym", "Lack of disposable income — a person has plenty of money but simply dislikes exercising"]}'::jsonb, '{"answer": 0, "explain": "Awareness of provision is exactly this: the session exists, but people don''t know. B describes the opposite (good provision, well advertised), and C/D describe personal choice, not a barrier."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:mcq:d95b313b', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'mcq', 'mcq', 1, '{"question": "Which of these is most likely to reduce participation by removing visible role models for a group?", "options": ["Lack of transport links to the leisure centre", "Unequal media coverage by gender or ethnicity", "A short-term rise in the price of replica kit for one single season only", "A minor change to a competition''s kick-off time"]}'::jsonb, '{"answer": 1, "explain": "Unequal media coverage directly reduces how visible role models are for a group. Transport, kit prices and kick-off times are barriers, but they don''t remove role models."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:mcq:bac2b556', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'mcq', 'mcq', 1, '{"question": "Someone knows a low-cost, beginner-friendly class exists two streets from their house, but has never been able to attend because there is no bus route and they don''t drive. Which barrier is most directly shown here?", "options": ["Lack of awareness of appropriate provision", "Lack of positive sporting role models", "Lack of appropriate activity provision", "Lack of transport"]}'::jsonb, '{"answer": 3, "explain": "They already know the class exists and it''s suitable — the problem is physically getting there, which is lack of transport, not awareness or role models."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:mcq:773a3d26', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'mcq', 'mcq', 1, '{"question": "A teenager says nobody in their family has ever really done sport, and nobody at home encourages them to try a new club. Which barrier does this describe?", "options": ["No one at home plays sport or encourages them to join in", "Lack of transport to any sports facility that is reasonably nearby", "Unequal media coverage of the sport in question", "Lack of disposable income to pay for equipment"]}'::jsonb, '{"answer": 0, "explain": "No sporting habit or encouragement at home describes the barrier of missing family role models and support — not transport, media coverage or cost, which aren''t mentioned here."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:tf:dc5a1473', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'tf', 'tf', 1, '{"question": "A ''barrier'' and a ''user group'' mean exactly the same thing."}'::jsonb, '{"answer": false, "explain": "A user group is WHO might take part. A barrier is WHAT stops or discourages them. They are related ideas but not the same thing."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:tf:36cf0651', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'tf', 'tf', 1, '{"question": "Lack of disposable income can include the added-up cost of kit, membership fees and travel."}'::jsonb, '{"answer": true, "explain": "All three costs can combine, so someone in work can still be short of the spare money needed to take part."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:tf:e7cc8dce', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'tf', 'tf', 1, '{"question": "Lack of transport can only ever be a barrier for people who do not own a car."}'::jsonb, '{"answer": false, "explain": "It can also affect car owners if the nearest suitable facility is too far, or if fuel and parking costs are too high — it''s about practically reaching the venue, not just car ownership."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:tf:9804ca8c', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'tf', 'tf', 1, '{"question": "''Lack of appropriate provision'' and ''lack of awareness of provision'' describe exactly the same problem."}'::jsonb, '{"answer": false, "explain": "One means no suitable session exists; the other means a suitable session exists but people don''t know about it. The exam rewards spotting the difference."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:tf:024e651f', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'tf', 'tf', 1, '{"question": "Positive role models can come from within a person''s own family, not only from elite sport."}'::jsonb, '{"answer": true, "explain": "A family member who takes part in and encourages sport is a positive role model too, just as much as a professional athlete can be."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:tf:fb3f14cc', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'tf', 'tf', 1, '{"question": "Unequal media coverage by gender or ethnicity can reduce participation by reducing the number of visible role models."}'::jsonb, '{"answer": true, "explain": "Less coverage means fewer visible role models for that group, which can make a sport feel less ''for them'' before they even try it."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:learn:334d7cb1', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'learn', 'mcq', 1, '{"readingTitle": "What a ''barrier'' is — and why it''s not the same as a user group", "reading": "<h4>The idea</h4>\n<ul>\n<li>A <strong>barrier</strong> is anything that stops or discourages someone from taking part in sport — a practical, personal or social obstacle in their way.</li>\n<li>This is a different idea from a <strong>user group</strong>, which you met in 1.1. A user group is <em>WHO</em> might take part (such as teenagers or carers). A barrier is <em>WHAT</em> stops them.</li>\n</ul>\n<h4>The exam skill: link the barrier to a group, and explain why</h4>\n<ul>\n<li>Weak answer: <em>\"A barrier is lack of transport.\"</em> That names a barrier but shows no understanding.</li>\n<li>Strong answer: <em>\"Lack of transport is a barrier that particularly affects people without a car, such as some carers, because they cannot physically reach a leisure centre that is far from public transport routes.\"</em></li>\n<li>The mark almost always comes from <strong>naming the barrier, saying who it affects most, and explaining why</strong> — not from the name on its own.</li>\n</ul>\n<h4>One barrier can affect several groups</h4>\n<ul>\n<li>A barrier is rarely limited to one group. Lack of disposable income can affect unemployed people, some carers and some teenagers all at once — but the exam still rewards a clear, well-explained link to one named group.</li>\n</ul>", "question": "Which of these best explains the difference between a ''user group'' and a ''barrier''?", "options": ["A user group is a category of people; a barrier is something that stops or discourages them from taking part", "They are two different names for exactly the same idea, so either word can always be used instead of the other", "A barrier is a category of people, and a user group is what stops them taking part in sport", "A user group only ever refers to teenagers, while a barrier only ever refers to cost"]}'::jsonb, '{"answer": 0, "explain": "A user group is WHO might take part; a barrier is WHAT stops them. They are related, but they are not interchangeable words, and ''barrier'' is not limited to cost."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:learn:a63e6204', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'learn', 'mcq', 1, '{"readingTitle": "Barriers of money, time and getting there", "reading": "<p>Several of the most commonly tested barriers come down to <strong>having enough money, enough free time, or a way to get there</strong>.</p>\n<h4>Work and money</h4>\n<ul>\n<li><strong>Employment</strong> — people in work can face long or awkward hours (shifts, evenings, weekends) that clash with the times sessions run.</li>\n<li><strong>Unemployment</strong> — people without a job often have very little spare money, so cost becomes the barrier instead of time.</li>\n<li><strong>Lack of disposable income</strong> — even people in work may not have money left over for the cost of kit, a membership fee and the travel to get there. All three add up.</li>\n</ul>\n<h4>Time and family</h4>\n<ul>\n<li><strong>Family commitments</strong> and <strong>being a carer</strong> — looking after children or a relative leaves little free time to take part, and sessions rarely fit around caring duties.</li>\n</ul>\n<h4>Getting there</h4>\n<ul>\n<li><strong>Lack of transport</strong> — even a great, affordable session is no use if someone cannot physically reach the venue, especially in areas with poor public transport.</li>\n</ul>", "question": "A person works irregular evening shifts and says they can never get to a 6pm class. Which barrier is this?", "options": ["Lack of transport", "Employment (long or awkward working hours)", "Lack of positive family role models", "Unequal media coverage of the sport they want to play"]}'::jsonb, '{"answer": 1, "explain": "Their working hours, not transport, role models or media coverage, are what clash with the session time — this is the employment barrier."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:learn:aaae41af', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'learn', 'mcq', 1, '{"readingTitle": "Barriers of role models, provision and awareness", "reading": "<h4>Provision</h4>\n<ul>\n<li><strong>No awareness that a suitable session exists</strong> — this is a different problem: the session or facility already exists locally, but the person has never heard about it, so it might as well not exist for them.</li>\n<li><strong>No suitable activity available nearby</strong> — sometimes there is simply no session, club or facility close enough to someone, for their age, ability or interest.</li>\n</ul>\n<h4>Role models</h4>\n<ul>\n<li><strong>No encouragement or example set at home</strong> — if the adults around someone never took part in sport or actively discourage it, a young person gets far less encouragement to start.</li>\n<li><strong>No inspiring sports stars to look up to</strong> — without visible people to admire or copy in a sport, it can feel like \"not for someone like me\", which lowers the urge to try it.</li>\n</ul>\n<h4>Why the exam separates these two \"provision\" barriers</h4>\n<ul>\n<li>Examiners reward you for spotting the difference: one is \"it isn''t there\", the other is \"it''s there, but nobody told them\". A good promotion campaign fixes the second even when nothing new has been built.</li>\n</ul>", "question": "A leisure centre already runs a low-cost beginners'' swimming class, but almost nobody local knows it exists. Which barrier is this?", "options": ["Lack of positive sporting role models", "Lack of transport to the leisure centre", "Lack of awareness of appropriate provision", "Lack of appropriate activity provision for this specific age group"]}'::jsonb, '{"answer": 2, "explain": "The session already exists — the problem is that people don''t know about it. That is awareness of provision, not a missing session, transport or role models."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:learn:941c8eff', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'learn', 'mcq', 1, '{"readingTitle": "Media coverage — and the exam skill in action", "reading": "<h4>Unequal media coverage</h4>\n<ul>\n<li>Some sports, genders and ethnic groups get far less media coverage than others. Less coverage means <strong>fewer visible role models</strong> to inspire people, and sometimes lazy stereotyping about who \"should\" play a sport.</li>\n<li>This is a barrier because it works on people''s <em>attitudes</em> before they even reach a leisure centre — if you rarely see people like you competing on TV, it can feel like the sport isn''t meant for you.</li>\n<li>Unequal coverage by <strong>gender</strong> and by <strong>ethnicity</strong> are both named in the specification, and both work the same way: less visibility, fewer role models, lower participation.</li>\n</ul>\n<h4>Worked example of the exam skill</h4>\n<ul>\n<li><strong>Barrier:</strong> unequal media coverage by gender.</li>\n<li><strong>Group it affects:</strong> girls and women taking up a sport that is rarely shown on TV.</li>\n<li><strong>Why:</strong> with few elite women visible in that sport, girls have fewer role models to copy and may not realise the pathway exists — so fewer take it up.</li>\n</ul>\n<h4>Putting it all together</h4>\n<ul>\n<li>Whatever barrier you are asked about, the strongest answers always finish the sentence: \"...which stops or discourages [named group], because [reason].\"</li>\n</ul>", "question": "Why does unequal media coverage by gender or ethnicity reduce participation?", "options": ["It gives fewer visible role models and can reinforce stereotypes about who plays a sport", "It has no real effect at all on whether people choose to take part in a sport", "It always makes tickets for live matches more expensive to buy", "It only affects people who already play sport at a professional, elite level, not anyone starting out"]}'::jsonb, '{"answer": 0, "explain": "Fewer visible role models and reinforced stereotypes lower participation before someone even tries a sport — it is not really about ticket prices, and it affects beginners, not only elite performers."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:misc:57ebb193', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> To answer a barriers question, I just need to name a barrier, like ''lack of transport''.</p><p><strong>✅ The correct idea:</strong> Naming is only the first mark at most. The examiner is looking for you to link the barrier to a GROUP it affects and WHY. Level 1 answer: \"A barrier is lack of transport.\" Full-marks answer: \"Lack of transport is a barrier for carers who don''t drive, because they cannot physically reach a leisure centre without a reliable bus route.\" The difference is the group and the reason.</p>", "question": "An ''Explain'' question asks about a barrier to participation. What earns the marks?", "options": ["Naming as many different barriers as you possibly can, without explaining any of them", "Naming the barrier, then the group it affects and a reason", "Writing the barrier''s name in bold", "Describing your own weekend sport in detail"]}'::jsonb, '{"answer": 1, "explain": "Explain = point + reason, applied to a group. Naming the barrier alone, or listing several, does not show the understanding the mark scheme rewards."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:misc:de736453', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A ''barrier'' and a ''user group'' are basically the same thing.</p><p><strong>✅ The correct idea:</strong> They are two different ideas the exam keeps side by side. A user group is a category of PEOPLE (who might take part). A barrier is something that STOPS people taking part (cost, transport, lack of provision). A question can ask you to link them — ''which barrier affects this group?'' — but they are not the same word.</p>", "question": "Which of these is a barrier, not a user group?", "options": ["Teenagers", "Lack of disposable income", "People with disabilities", "Retired people and the over-60s"]}'::jsonb, '{"answer": 1, "explain": "Lack of disposable income is something that stops participation — a barrier. The other three are categories of people — user groups."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:misc:985e29a6', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Lack of appropriate provision'' and ''lack of awareness of appropriate provision'' both just mean ''there''s no session''.</p><p><strong>✅ The correct idea:</strong> They describe two different problems. Lack of appropriate provision means no suitable session or facility actually exists nearby. Lack of awareness of provision means a suitable session DOES exist, but the person has never heard about it — so, from their point of view, it might as well not exist. Fixing the first needs new provision; fixing the second just needs better promotion.</p>", "question": "A council already runs a free wheelchair basketball session, but hardly anyone locally knows about it. Which barrier is shown?", "options": ["Lack of appropriate activity provision for that age or ability group", "Lack of awareness of appropriate provision", "Lack of positive sporting role models", "Lack of disposable income"]}'::jsonb, '{"answer": 1, "explain": "The session already exists — the problem is that people don''t know about it, which is lack of awareness, not a missing session, role models or cost."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:misc:12314918', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Unequal media coverage as a barrier only really matters to people who want to become professional athletes.</p><p><strong>✅ The correct idea:</strong> It affects far more than future professionals. Media coverage shapes whether ORDINARY people feel a sport is ''for them'' at all. If a group rarely sees people like themselves competing on TV, that can put someone off ever trying a beginner session — long before elite performance is anywhere in the picture.</p>", "question": "Who can unequal media coverage put off from taking part in a sport?", "options": ["Only people who are already competing at a professional, elite level, and nobody else at all", "Beginners deciding whether to try a sport at all, not just elite performers", "Nobody — media coverage has no effect on participation", "Only people who already own a season ticket"]}'::jsonb, '{"answer": 1, "explain": "Fewer visible role models can put off a complete beginner from ever trying a sport — the effect starts long before anyone reaches elite level."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:tips:c5a090ae', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Barriers questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one barrier to participation [1]\" = write one barrier name, nothing more.</li>\n<li><strong>Describe</strong> — say what the barrier is or how it works. \"Describe a barrier facing unemployed people [2]\" = give the features of that barrier.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain why lack of transport can stop someone taking part\" = the barrier <em>plus</em> why it stops them.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed; [4] in Section B wants points applied to the scenario.</p>", "question": "A question says: ''Identify two barriers to participation [2]''. What is the safest answer?", "options": ["A long paragraph about one barrier", "Two barrier names", "One barrier name explained in detail", "A list of six barriers"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one barrier, or listing six, wastes time and risks the examiner marking only the first two anyway."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:tips:725966d7', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the barrier, the group, AND why", "reading": "<p>The single most common way to lose marks here is stopping at the name. Build every answer as <strong>barrier → group it affects → reason</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Lack of transport.\"</li>\n<li><strong>✅ full marks:</strong> \"Lack of transport is a barrier for people without a car, because they cannot physically reach a leisure centre that isn''t on a bus route.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named place, a named person). Then you must use a detail <em>from that scenario</em>, not a general example.</p>", "question": "In a Section B scenario question about a named person facing a barrier, your explanation should come from...", "options": ["absolutely any barrier that you happen to remember", "the scenario you are given", "a famous athlete''s biography", "your own school only"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general point that ignores the scenario is capped."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:tips:36c38e12', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where barriers appear + sentence starters", "reading": "<p><strong>Where it shows up:</strong> barriers appear as quick recall in <strong>Section A</strong> (identify/state/describe), and as applied points in <strong>Section B</strong> scenarios about a named person or centre. They also feed <strong>Section C</strong> 8-mark answers about how a provider could increase participation by tackling barriers.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the barriers in themes (money/time, getting there, role models, provision, media) so you can always recall a few.</li>\n<li>For every barrier, memorise <em>one</em> typical group it affects, and <em>why</em> — that reason is usually where the mark is.</li>\n<li>Never confuse \"lack of provision\" (nothing suitable exists) with \"lack of awareness of provision\" (it exists but nobody knows) — the exam tests the difference.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One barrier affecting this group is… because…\"</li>\n<li>\"This barrier stops them because… so the provider could…\"</li>\n<li>\"However, this change might not remove every barrier, because…\"</li>\n</ul>", "question": "Why is it useful to link a barrier to a specific reason it stops a group, rather than just naming it?", "options": ["It fills space in the answer", "It shows understanding of HOW and WHY participation is affected", "It means the barrier no longer applies", "It replaces the need to name any barrier at all, so nothing else is required"]}'::jsonb, '{"answer": 1, "explain": "Naming plus a reason shows real understanding of how the barrier works — the kind of point the mark scheme is built to reward."}'::jsonb),
('sport-studies:1-2-barriers-to-participation:fib:43a75247', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'fib', 'fib', 1, '{"question": "A barrier to participation is anything that stops or _____ someone from taking part in sport.", "blankOptions": {"B1": ["disposable", "discourages", "coverage", "transport"]}}'::jsonb, '{"blanks": {"B1": "discourages"}}'::jsonb),
('sport-studies:1-2-barriers-to-participation:fib:b44e5566', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'fib', 'fib', 1, '{"question": "People in work can face long or _____ hours that clash with when sessions run.", "blankOptions": {"B1": ["disposable", "awkward", "discourages", "awareness"]}}'::jsonb, '{"blanks": {"B1": "awkward"}}'::jsonb),
('sport-studies:1-2-barriers-to-participation:fib:f8b76338', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'fib', 'fib', 1, '{"question": "A lack of _____ income means there is no spare money for kit, membership or travel.", "blankOptions": {"B1": ["transport", "coverage", "disposable", "awkward"]}}'::jsonb, '{"blanks": {"B1": "disposable"}}'::jsonb),
('sport-studies:1-2-barriers-to-participation:fib:bb7661a2', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'fib', 'fib', 1, '{"question": "Even a great session is no use if someone cannot physically reach it because of a lack of _____.", "blankOptions": {"B1": ["awkward", "awareness", "discourages", "transport"]}}'::jsonb, '{"blanks": {"B1": "transport"}}'::jsonb),
('sport-studies:1-2-barriers-to-participation:fib:578a7f6a', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'fib', 'fib', 1, '{"question": "Lack of _____ of appropriate provision means a session already exists locally, but people have never heard about it.", "blankOptions": {"B1": ["disposable", "discourages", "awareness", "transport"]}}'::jsonb, '{"blanks": {"B1": "awareness"}}'::jsonb),
('sport-studies:1-2-barriers-to-participation:fib:981d64f7', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'fib', 'fib', 1, '{"question": "Unequal media _____ by gender or ethnicity means fewer visible role models for some groups.", "blankOptions": {"B1": ["awareness", "coverage", "transport", "disposable"]}}'::jsonb, '{"blanks": {"B1": "coverage"}}'::jsonb),
('sport-studies:1-2-barriers-to-participation:match:9f12c5ce', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Barrier to participation”?", "options": ["Looking after children or a relative, leaving little free time to attend sessions", "Not having a practical way of physically reaching a facility or venue", "Anything that stops or discourages someone from taking part in sport", "Long or awkward working hours that clash with when sessions run"]}'::jsonb, '{"answer": 2, "explain": "“Barrier to participation” means: Anything that stops or discourages someone from taking part in sport"}'::jsonb),
('sport-studies:1-2-barriers-to-participation:match:869e900d', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Employment”?", "options": ["Looking after children or a relative, leaving little free time to attend sessions", "Having very little spare money because a person is without a job", "Long or awkward working hours that clash with when sessions run", "Not having a practical way of physically reaching a facility or venue"]}'::jsonb, '{"answer": 2, "explain": "“Employment” means: Long or awkward working hours that clash with when sessions run"}'::jsonb),
('sport-studies:1-2-barriers-to-participation:match:1052da96', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Unemployment”?", "options": ["Not having a practical way of physically reaching a facility or venue", "Long or awkward working hours that clash with when sessions run", "Having nobody visible in sport or at home to admire, copy or be encouraged by", "Having very little spare money because a person is without a job"]}'::jsonb, '{"answer": 3, "explain": "“Unemployment” means: Having very little spare money because a person is without a job"}'::jsonb),
('sport-studies:1-2-barriers-to-participation:match:abf7cb64', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Family commitments / being a carer”?", "options": ["Not knowing that a suitable local session or facility already exists", "Anything that stops or discourages someone from taking part in sport", "Looking after children or a relative, leaving little free time to attend sessions", "Not having spare money left over for kit, membership and travel costs"]}'::jsonb, '{"answer": 2, "explain": "“Family commitments / being a carer” means: Looking after children or a relative, leaving little free time to attend sessions"}'::jsonb),
('sport-studies:1-2-barriers-to-participation:match:4a94f7f6', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Lack of disposable income”?", "options": ["Not knowing that a suitable local session or facility already exists", "Having very little spare money because a person is without a job", "Having nobody visible in sport or at home to admire, copy or be encouraged by", "Not having spare money left over for kit, membership and travel costs"]}'::jsonb, '{"answer": 3, "explain": "“Lack of disposable income” means: Not having spare money left over for kit, membership and travel costs"}'::jsonb),
('sport-studies:1-2-barriers-to-participation:match:e1c9ebdb', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Lack of transport”?", "options": ["Not having spare money left over for kit, membership and travel costs", "Having very little spare money because a person is without a job", "Not having a practical way of physically reaching a facility or venue", "Not knowing that a suitable local session or facility already exists"]}'::jsonb, '{"answer": 2, "explain": "“Lack of transport” means: Not having a practical way of physically reaching a facility or venue"}'::jsonb),
('sport-studies:1-2-barriers-to-participation:match:ae076952', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Lack of positive role models”?", "options": ["Long or awkward working hours that clash with when sessions run", "Having nobody visible in sport or at home to admire, copy or be encouraged by", "Not knowing that a suitable local session or facility already exists", "Anything that stops or discourages someone from taking part in sport"]}'::jsonb, '{"answer": 1, "explain": "“Lack of positive role models” means: Having nobody visible in sport or at home to admire, copy or be encouraged by"}'::jsonb),
('sport-studies:1-2-barriers-to-participation:match:b47f4bf0', 'sport-studies', 'sport-studies:1-2-barriers-to-participation', '1.2 Barriers to Participation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Lack of awareness of provision”?", "options": ["Not having a practical way of physically reaching a facility or venue", "Looking after children or a relative, leaving little free time to attend sessions", "Anything that stops or discourages someone from taking part in sport", "Not knowing that a suitable local session or facility already exists"]}'::jsonb, '{"answer": 3, "explain": "“Lack of awareness of provision” means: Not knowing that a suitable local session or facility already exists"}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:exam:33b02337', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is the best example of using transport to remove a barrier to participation?", "options": ["Printing a new price list and handing it out at reception", "Running a free pick-up minibus service from a nearby estate to the leisure centre", "Adding a well-known professional athlete''s photo to the centre''s website homepage", "Extending the opening hours of the reception desk each evening"], "hint": "Think about what actually changes whether a group can physically reach a venue.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Running a free pick-up minibus service from a nearby estate to the leisure centre.</strong></p>\n<ul>\n<li>A pick-up service directly solves a transport barrier by getting people to the venue.</li>\n<li>A price list, a website photo, and reception hours are pricing, promotion and staffing changes, not transport.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:mcq:751ed339', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'mcq', 'mcq', 1, '{"question": "A leisure centre currently only runs sessions during the working week daytime. Which change is the clearest example of the ''provision'' solution?", "options": ["Printing a brand new leaflet that only describes the sessions already running in the daytime", "Adding an evening or weekend session aimed at people who work in the daytime", "Charging slightly less money for the existing daytime sessions", "Employing an extra receptionist to answer the phone during the day"]}'::jsonb, '{"answer": 1, "explain": "Provision means changing WHAT is on offer — new sessions at new times. A new leaflet is promotion, a lower price is pricing, and extra reception staff changes neither the offer nor who can attend."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:mcq:f7612b2e', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'mcq', 'mcq', 1, '{"question": "A local swimming club wants more teenage girls to join. Which action best uses a ''promotion'' solution?", "options": ["Fitting a hearing loop in the changing rooms for members with a hearing impairment", "Adding extra car-parking spaces outside the venue for visiting families", "Featuring a respected female swimmer from the local area in its adverts", "Building a wheelchair-accessible ramp at the main entrance"]}'::jsonb, '{"answer": 2, "explain": "Using a local role model in adverts targets the group directly — that''s promotion. Hearing loops, parking and ramps are facilities, transport and access changes, not promotion."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:mcq:d2d51955', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'mcq', 'mcq', 1, '{"question": "Several older residents say they would attend a gentle exercise class but have no way of reaching the venue. Which solution most directly removes this barrier?", "options": ["A free taster session with absolutely no charge at all for the very first visit", "A dedicated pick-up service or an extra bus route to the venue", "A louder advert broadcast on local commercial radio", "A slightly cheaper price for the same weekly class"]}'::jsonb, '{"answer": 1, "explain": "The barrier described is getting there, not cost or awareness — so a pick-up service or extra bus route is the solution that actually removes it."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:mcq:cc9aa0d7', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'mcq', 'mcq', 1, '{"question": "A member with a visual impairment struggles to find their way around a large sports centre. Which solution addresses this specific barrier?", "options": ["Braille or tactile signage placed clearly around the building", "A free taster session offered to new visually impaired members", "An extra evening class added to the existing weekly timetable", "A reduced membership price for the first three months"]}'::jsonb, '{"answer": 0, "explain": "Braille or tactile signage lets a visually impaired person navigate independently. A taster session, a new class time, and a lower price do not solve a navigation barrier."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:mcq:e2913936', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'mcq', 'mcq', 1, '{"question": "A centre has a step at the main entrance and narrow changing-room doorways. Which change best improves ''access'' for wheelchair users?", "options": ["Running more sessions later in the evening for working members", "Advertising the centre repeatedly using a well-known local wheelchair athlete", "Fitting a ramp at the entrance and widening the changing-room doorways", "Offering a discount for the first month of membership"]}'::jsonb, '{"answer": 2, "explain": "A ramp and wider doorways change the physical route into and around the building — that is access. The other options are provision, promotion and pricing instead."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:mcq:43608b4d', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'mcq', 'mcq', 1, '{"question": "Which of these answers best links a solution to both a barrier and a user group?", "options": ["Leisure centres should really try to offer more activities generally", "Free taster sessions remove the cost barrier for unemployed people, so they can try an activity first", "Free taster sessions are honestly thought to be a fantastic idea for absolutely every leisure centre in the entire country", "Cost is sometimes a problem for people who do not have very much money"]}'::jsonb, '{"answer": 1, "explain": "This option names the solution, the exact barrier (cost) and the exact group (unemployed people). The others are vague, generic, or name a barrier with no linked fix."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:tf:290c7d19', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'tf', 'tf', 1, '{"question": "A solution only earns full marks in the exam when it is linked to a specific barrier and a specific user group."}'::jsonb, '{"answer": true, "explain": "Naming a solution on its own rarely earns the marks — the mark scheme rewards the solution PLUS the barrier it removes PLUS the group it helps."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:tf:a5633778', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'tf', 'tf', 1, '{"question": "Provision means advertising an activity, rather than changing its timing or sessions."}'::jsonb, '{"answer": false, "explain": "Provision changes WHAT is on offer — new sessions, activities or times. Advertising an existing offer differently is promotion, a separate solution."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:tf:7f02bc0a', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'tf', 'tf', 1, '{"question": "A pool hoist is an example of appropriate facilities and equipment for some user groups."}'::jsonb, '{"answer": true, "explain": "A pool hoist lets a person with limited mobility enter and exit a pool safely — a facilities-and-equipment solution matched to that barrier."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:tf:a2dbb20c', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'tf', 'tf', 1, '{"question": "Braille or tactile signage is only ever useful for wheelchair users."}'::jsonb, '{"answer": false, "explain": "Braille and tactile signage help people with a visual impairment. ''People with disabilities'' covers a wide range, so the right solution must match the actual barrier."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:tf:0698b999', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'tf', 'tf', 1, '{"question": "A free taster session is an example of an initiative that can help remove the cost barrier."}'::jsonb, '{"answer": true, "explain": "A taster session lets a group try an activity before paying anything, which removes the fear of committing money to something unfamiliar."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:tf:a4ba937c', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'tf', 'tf', 1, '{"question": "Improving access always means exactly the same thing as adding more car-parking spaces."}'::jsonb, '{"answer": false, "explain": "Access covers the whole route into and around a venue — ramps, doorways, ground-floor changing rooms and clear paths — not only parking."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:learn:ae5e05f7', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'learn', 'mcq', 1, '{"readingTitle": "Linking a solution to its barrier and its user group — the exam skill", "reading": "<h4>Why ''just listing solutions'' fails</h4>\n<ul>\n<li>Every solution in this topic exists to remove a specific <strong>barrier</strong> (Topic 1.2) for a specific <strong>user group</strong> (Topic 1.1). A solution written on its own, with no barrier and no group named, earns little or nothing.</li>\n<li>Weak answer: <em>\"Leisure centres could run more taster sessions.\"</em> This names a solution but shows no understanding of what it actually fixes.</li>\n<li>Strong answer: <em>\"Free taster sessions remove the cost barrier facing unemployed people, letting them try an activity before committing any money.\"</em></li>\n</ul>\n<h4>Build every answer the same way</h4>\n<ul>\n<li>Step 1 — name the <strong>solution</strong>.</li>\n<li>Step 2 — say which <strong>barrier</strong> it removes.</li>\n<li>Step 3 — say which <strong>user group</strong> it helps, and why.</li>\n</ul>\n<p>This three-step shape is what most Section B marks in this topic actually reward — not the name of the solution by itself.</p>", "question": "Which of these shows the strongest understanding of a solution to a barrier?", "options": ["A description linking the solution to the specific barrier it removes and the group it helps", "A long list naming every single possible solution a leisure centre could ever possibly consider offering", "The name of one solution with nothing else added", "A description of a barrier with no solution mentioned at all"]}'::jsonb, '{"answer": 0, "explain": "Marks come from linking a solution to the specific barrier it removes and the group it helps — not from a long list, a bare name, or a barrier alone with no fix."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:learn:203490fd', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'learn', 'mcq', 1, '{"readingTitle": "Provision, promotion and transport", "reading": "<h4>Provision — the right programme, at the right time</h4>\n<ul>\n<li><strong>Provision</strong> means offering appropriate programmes, sessions, activities and <strong>times</strong> aimed at a specific user group, rather than one timetable expected to suit everybody.</li>\n<li>Example: a crèche-supported morning class for parents; a low-impact, sociable daytime session for retired people; a cheap after-school club for teenagers.</li>\n</ul>\n<h4>Promotion — telling the right people, in the right way</h4>\n<ul>\n<li><strong>Targeted advertising and promotion</strong> reaches a specific group directly, instead of one generic advert aimed at nobody in particular.</li>\n<li>Using <strong>role models</strong> from a group (or connected to it) can make an activity feel like \"people like me do this\".</li>\n<li><strong>Initiatives and incentives</strong> — such as a free taster session — let a group try an activity with nothing to lose, which can remove the fear of an unfamiliar or costly commitment.</li>\n</ul>\n<h4>Transport — getting there in the first place</h4>\n<ul>\n<li>A brilliant session is no use if a group cannot reach the venue. <strong>Increased and appropriate transport</strong> (extra buses, a pick-up service, better links to public transport) removes this barrier directly.</li>\n</ul>", "question": "A leisure centre features a well-known local wheelchair basketball player in its adverts. This is mainly an example of...", "options": ["improved access to the building itself", "using a role model as a promotion strategy", "appropriate pricing for a user group", "increasing the transport available to the site"]}'::jsonb, '{"answer": 1, "explain": "Featuring a figure connected to a group in adverts is a promotion strategy (a role model), not a change to access, price or transport."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:learn:4792af9f', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'learn', 'mcq', 1, '{"readingTitle": "Facilities, equipment and access", "reading": "<h4>Appropriate facilities and equipment</h4>\n<ul>\n<li>Different user groups need different physical adjustments to take part safely and independently. Examples the specification highlights include:</li>\n<li><strong>Pool hoists</strong> — allow a person with limited mobility to enter and exit a swimming pool safely.</li>\n<li><strong>Hearing loops</strong> — let a person with a hearing impairment follow instructions or announcements clearly.</li>\n<li><strong>Braille or tactile signage</strong> — lets a person with a visual impairment navigate a building independently.</li>\n<li>These are examples for a <strong>range of disabilities</strong>, not only wheelchair users — the right piece of equipment should match the specific barrier a group actually faces.</li>\n</ul>\n<h4>Improved access</h4>\n<ul>\n<li><strong>Access</strong> is broader than one piece of equipment — it means the whole route into and around a facility (ramps, wide doorways, ground-floor changing rooms, clear paths) is usable by all user groups, not just the majority.</li>\n</ul>", "question": "A hearing loop fitted in a sports hall is a solution that mainly addresses...", "options": ["a transport barrier for people who live a very long way indeed from the venue", "a facilities and equipment barrier for people with a hearing impairment", "a pricing barrier for economically disadvantaged people", "a promotion barrier caused by a lack of advertising"]}'::jsonb, '{"answer": 1, "explain": "A hearing loop removes a specific facilities-and-equipment barrier — it does not change transport, price, or how the session is advertised."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:learn:dece391e', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'learn', 'mcq', 1, '{"readingTitle": "Pricing solutions", "reading": "<h4>Appropriate pricing for all user groups</h4>\n<ul>\n<li>Cost is one of the most common barriers (Topic 1.2), so pricing is one of the most tested solutions.</li>\n<li><strong>Concessions</strong> — reduced prices for groups such as students, unemployed people or over-60s.</li>\n<li><strong>Free taster sessions</strong> — let a group try an activity before paying anything at all.</li>\n<li><strong>Free or reduced-price equipment</strong> — removes the barrier of needing to buy kit before you can even start.</li>\n</ul>\n<h4>Pricing must actually fit the group</h4>\n<ul>\n<li>A concession that is still too expensive for the group it targets fixes nothing. Good answers check that the pricing change realistically removes the cost barrier for that specific group.</li>\n</ul>", "question": "Which of these is the best example of an ''appropriate pricing'' solution?", "options": ["Raising every single price so that the centre simply earns more money overall", "Offering a free taster session so a group can try an activity before paying", "Removing the reception desk from the building entirely", "Running the same single advert on local radio for every group"]}'::jsonb, '{"answer": 1, "explain": "A free taster session removes the cost barrier before anyone commits money. Raising prices, removing reception, or a single generic advert are not pricing solutions at all."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:misc:88165ffe', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If I just name a solution like ''more taster sessions'', that should get me the marks.</p><p><strong>✅ The correct idea:</strong> Naming a solution alone rarely earns the marks. Weak answer: \"Centres could run more taster sessions.\" Full-marks answer: \"Free taster sessions remove the cost barrier facing unemployed people, letting them try an activity before paying anything.\" The mark is for the barrier AND the group, not the solution''s name by itself.</p>", "question": "What is missing from the answer ''Centres could run more taster sessions''?", "options": ["Nothing — the answer is already complete", "The specific barrier it removes and the user group it helps", "A much longer list of other possible solutions that could be tried", "The exact price of the taster session"]}'::jsonb, '{"answer": 1, "explain": "The name of the solution alone shows no understanding — the marks need the barrier it removes and the group it helps attached to it."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:misc:17db2c07', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Provision and promotion are basically the same thing — they''re both about getting more people to sessions.</p><p><strong>✅ The correct idea:</strong> They are two different solutions. Provision changes WHAT is on offer (the sessions, times and activities themselves). Promotion changes whether people KNOW about it and want to attend (adverts, role models, incentives). A centre can have perfect provision that nobody has ever heard of, and perfect promotion for a timetable that suits nobody.</p>", "question": "A centre adds a new Saturday morning class. This is an example of...", "options": ["promotion, because it might attract new members", "provision, because it changes what sessions are on offer", "pricing, because Saturday classes usually cost more", "transport, because it is generally easier to reach on a Saturday"]}'::jsonb, '{"answer": 1, "explain": "Adding a new session changes the offer itself — that is provision, not promotion, pricing or transport."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:misc:7da904f5', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Facilities-and-equipment solutions like hearing loops or braille signage are only relevant to wheelchair users.</p><p><strong>✅ The correct idea:</strong> These solutions target specific, different disabilities — a hearing loop helps a hearing impairment, braille/tactile signage helps a visual impairment, a pool hoist helps limited mobility. ''People with disabilities'' covers a wide range, so a strong answer picks the solution that matches the actual barrier, rather than defaulting to ''wheelchair access'' every time.</p>", "question": "Which solution best matches a member who has a visual impairment?", "options": ["A much wider doorway added for wheelchair access", "Braille or tactile signage around the building", "A pool hoist for entering the water", "An extra evening session"]}'::jsonb, '{"answer": 1, "explain": "Braille/tactile signage matches a visual impairment specifically. The other options solve different barriers for different groups."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:misc:a2bf1b5d', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Any lower price automatically counts as an ''appropriate pricing'' solution.</p><p><strong>✅ The correct idea:</strong> A price cut only works as a solution if it actually removes the barrier for that specific group. A concession that is still unaffordable for an unemployed person fixes nothing. Strong answers check the pricing change realistically matches the group''s real situation, not just that a number went down.</p>", "question": "A centre lowers its price from £20 to £18 for unemployed members. Why might this NOT be an ''appropriate'' pricing solution?", "options": ["Because the price has changed at all", "Because £18 may still be unaffordable for this group", "Because the centre should never change any prices", "Because pricing solutions are never allowed in this topic"]}'::jsonb, '{"answer": 1, "explain": "A small reduction that is still unaffordable does not remove the real barrier — the change has to genuinely fit the group it targets."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:tips:5e40b5bc', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words and mark tariffs for this topic", "reading": "<p>Solutions questions vary a lot in length. Match your answer to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name a solution. \"Identify one solution to a transport barrier\" = one named idea, 1 mark.</li>\n<li><strong>Describe</strong> — say what the solution involves. \"Describe one way a centre could improve access\" = give the feature (e.g. a ramp, wider doorways).</li>\n<li><strong>Explain</strong> — give the reason, using the barrier AND the group. \"Explain how a centre could increase participation among carers\" = a solution <em>plus</em> the barrier it removes for that group.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two points, or one point developed with a reason; [4] in Section B wants points applied to the scenario, one barrier/group pair at a time.</p>", "question": "A question says: ''Identify one solution that could improve transport to a venue [1]''. What is the safest answer?", "options": ["A full explanation of every possible transport solution", "One named transport solution", "A description of a transport barrier instead", "A list of five different solutions"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [1] = one named idea, nothing more. Explaining fully or listing five solutions wastes time for no extra marks."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:tips:b176b275', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: solution → barrier → group", "reading": "<p>The single most common way to lose marks here is stopping at the solution''s name. Build every answer as <strong>solution → barrier it removes → group it helps</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"More taster sessions.\"</li>\n<li><strong>✅ full marks:</strong> \"Free taster sessions remove the cost barrier facing unemployed people, so they can try an activity before paying anything.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named centre, named groups). You must use a barrier and a group <em>from that scenario</em>, not a general example.</p>", "question": "In a Section B scenario about a named leisure centre, your solution should be linked to...", "options": ["absolutely any barrier you happen to remember", "the barrier and group given in the scenario", "a famous athlete you personally admire", "your own local gym only"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for linking your solution to the specific barrier and group described in the scenario in front of you."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:tips:67179787', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where solutions appear + sentence starters", "reading": "<p><strong>Where it shows up:</strong> solutions appear as quick recall in <strong>Section A</strong> (identify/state a solution), as applied points in <strong>Section B</strong> scenarios about increasing participation, and as the basis for <strong>Section C</strong> 8-mark answers evaluating how effective a range of solutions would really be.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the six solution types (provision, promotion, transport, facilities/equipment, access, pricing) so you can always recall a few.</li>\n<li>For every solution, memorise <em>one</em> barrier it removes and <em>one</em> group it helps — that pairing is usually where the mark is.</li>\n<li>In longer answers, weigh up limits (cost to the centre, one change not suiting every group) — that is where the top marks live.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One solution here is… which removes the barrier of… for…\"</li>\n<li>\"This works because…\"</li>\n<li>\"However, this solution might not fully work if… because…\"</li>\n</ul>", "question": "Why is weighing up a solution''s limits a useful point in a longer answer?", "options": ["It fills space with extra words", "It shows deeper understanding of how effective the solution really is", "It means the solution should never be attempted", "It completely replaces the need for mentioning any barrier or group at all"]}'::jsonb, '{"answer": 1, "explain": "Noticing a real limit (cost, or one group''s needs clashing with another''s) shows evaluation — the skill that lifts a Section C answer into the top band."}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:fib:3a0a74d4', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'fib', 'fib', 1, '{"question": "Offering the right programmes, sessions and _____ for a specific user group is called provision.", "blankOptions": {"B1": ["taster", "access", "times", "concession"]}}'::jsonb, '{"blanks": {"B1": "times"}}'::jsonb)
